import{_ as i,c as l,o as t,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.53：用户插件优先级、ACP 会话用量追踪","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.53.md","filePath":"changelog/v1.1.53.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.53.md"};function n(h,e,d,s,c,p){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-53-用户插件优先级、acp-会话用量追踪" tabindex="-1">v1.1.53：用户插件优先级、ACP 会话用量追踪 <a class="header-anchor" href="#v1-1-53-用户插件优先级、acp-会话用量追踪" aria-label="Permalink to “v1.1.53：用户插件优先级、ACP 会话用量追踪”">​</a></h1><p><strong>发布日期</strong>：2026年02月05日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新让用户插件可以覆盖内置插件，新增 ACP 会话用量追踪，修复了中止消息时的未处理错误，桌面端改进了文件操作和终端稳定性。</p><hr><h2 id="新功能-用户插件覆盖内置插件" tabindex="-1">新功能：用户插件覆盖内置插件 <a class="header-anchor" href="#新功能-用户插件覆盖内置插件" aria-label="Permalink to “新功能：用户插件覆盖内置插件”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>当用户插件和内置插件提供相同 provider 时，用户插件现在会优先生效。</p><h3 id="有什么用" tabindex="-1">有什么用？ <a class="header-anchor" href="#有什么用" aria-label="Permalink to “有什么用？”">​</a></h3><p>如果你对内置插件的行为不满意，可以编写自己的插件来替代它。比如你想自定义某个 provider 的认证方式，只需创建一个同名的用户插件即可。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>在 <code>.opencode/plugins/</code> 或 <code>~/.config/opencode/plugins/</code> 中创建与内置插件同名的插件文件，OpenCode 会自动使用你的版本。</p><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/12a-plugins-basics.html">插件基础</a></p><hr><h2 id="新功能-acp-会话用量追踪" tabindex="-1">新功能：ACP 会话用量追踪 <a class="header-anchor" href="#新功能-acp-会话用量追踪" aria-label="Permalink to “新功能：ACP 会话用量追踪”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>ACP（Agent Communication Protocol）现在支持会话级别的用量追踪。</p><h3 id="有什么用-1" tabindex="-1">有什么用？ <a class="header-anchor" href="#有什么用-1" aria-label="Permalink to “有什么用？”">​</a></h3><p>如果你通过 IDE 扩展（如 VS Code）使用 OpenCode，现在可以看到每个会话的 token 用量统计。</p><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/08b-acp.html">ACP 协议</a></p><hr><h2 id="改进-插件加载顺序" tabindex="-1">改进：插件加载顺序 <a class="header-anchor" href="#改进-插件加载顺序" aria-label="Permalink to “改进：插件加载顺序”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>用户插件现在在内置插件之后加载，确保���户插件可以正确覆盖内置行为。</p><hr><h2 id="问题修复-中止消息时的未处理错误" tabindex="-1">问题修复：中止消息时的未处理错误 <a class="header-anchor" href="#问题修复-中止消息时的未处理错误" aria-label="Permalink to “问题修复：中止消息时的未处理错误”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>当有排队消息时中止操作，可能会触发未处理的错误。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>中止操作现在能正确处理排队消息，不再出现未处理错误。</p><hr><h2 id="改进-桌面端" tabindex="-1">改进：桌面端 <a class="header-anchor" href="#改进-桌面端" aria-label="Permalink to “改进：桌面端”">​</a></h2><h3 id="文件外部打开" tabindex="-1">文件外部打开 <a class="header-anchor" href="#文件外部打开" aria-label="Permalink to “文件外部打开”">​</a></h3><p>新增按钮，可以在外部应用程序中打开文件。</p><h3 id="提示词输入改进" tabindex="-1">提示词输入改进 <a class="header-anchor" href="#提示词输入改进" aria-label="Permalink to “提示词输入改进”">​</a></h3><p>关闭评论按钮在提示词输入框中现在可见。当有权限请求或问题时，提示词输入框会自动隐藏。</p><h3 id="文件树折叠" tabindex="-1">文件树折叠 <a class="header-anchor" href="#文件树折叠" aria-label="Permalink to “文件树折叠”">​</a></h3><p>文件树现在可以独立折叠，不影响其他面板。</p><h3 id="修改文件颜色对比度" tabindex="-1">修改文件颜色对比度 <a class="header-anchor" href="#修改文件颜色对比度" aria-label="Permalink to “修改文件颜色对比度”">​</a></h3><p>修改文件的颜色对比度提高，更容易辨识。</p><hr><h2 id="改进-tui" tabindex="-1">改进：TUI <a class="header-anchor" href="#改进-tui" aria-label="Permalink to “改进：TUI”">​</a></h2><h3 id="对话框鼠标退出" tabindex="-1">对话框鼠标退出 <a class="header-anchor" href="#对话框鼠标退出" aria-label="Permalink to “对话框鼠标退出”">​</a></h3><p>对话框中的 &quot;esc&quot; 标签现在支持鼠标点击退出，不再只能用键盘。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用自定义插件</td><td>✅ 推荐升级</td></tr><tr><td>通过 IDE 使用 OpenCode</td><td>✅ 推荐升级</td></tr><tr><td>桌面端用户</td><td>✅ 推荐升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',49),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Load user plugins after built-in plugins</li><li>Fix unhandled errors when aborting with queued messages</li><li>User plugins override built-in plugins for the same provider (@rmk40)</li><li>Move Codex 5.3 model definition to plugin to avoid showing unsupported model to other users</li><li>Add session usage tracking to ACP (@SteffenDE)</li><li>Update transforms for GPT-5.3</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Allow mouse escape via &quot;esc&quot; labels in dialogs (@AksharP5)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Make close comment button visible in prompt input (@alexyaroshuk)</li><li>Hide prompt input when there are permissions requests or questions</li><li>More terminal stability fixes</li><li>Modified file color contrast in app for better visibility</li><li>Add button to open files in external applications</li><li>Allow toggling file tree closed independently</li><li>Stop showing SessionSkeleton on new workspace (@dbpolito)</li><li>Set workspace name earlier to improve creation and deletion (@dbpolito)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const u=i(o,[["render",n]]);export{m as __pageData,u as default};
